import { useState } from "react";
import { NavigationContainer } from "@react-navigation/native";
import { createNativeStackNavigator } from "@react-navigation/native-stack";
import { StatusBar } from "expo-status-bar";
import NewLearning from "./components/NewLearning";
import Schedule from "./components/Schedule";

const Stack = createNativeStackNavigator();

export default function App() {
  const [learningTitles, setLearningTitles] = useState([]);

  const addLearningTitle = (title) => {
    const cleanedTitle = title.trim();
    if (!cleanedTitle) {
      return;
    }

    setLearningTitles((prev) => [...prev, cleanedTitle]);
  };

  return (
    <NavigationContainer>
      <StatusBar style="auto" />
      <Stack.Navigator initialRouteName="Schedule">
        <Stack.Screen name="Schedule">
          {(props) => <Schedule {...props} learningTitles={learningTitles} />}
        </Stack.Screen>
        <Stack.Screen name="NewLearning">
          {(props) => (
            <NewLearning {...props} onAddTitle={addLearningTitle} />
          )}
        </Stack.Screen>
      </Stack.Navigator>
    </NavigationContainer>
  );
}
